import datetime

now = datetime.datetime.now(datetime.timezone.utc)

alerts = []
for case in items:
    case_id = case.get('id')
    case_type = case.get('after_sale_type')
    status = case.get('after_sale_status')

    # 争议证据 24h 倒计时
    evidence_deadline = case.get('evidence_deadline')
    if evidence_deadline:
        try:
            deadline = datetime.datetime.fromisoformat(evidence_deadline.replace('Z', '+00:00'))
            remaining = (deadline - now).total_seconds() / 3600
            if remaining < 0:
                alerts.append({
                    'case_id': case_id,
                    'type': 'evidence_overdue',
                    'deadline': evidence_deadline,
                    'remaining_hours': round(remaining, 1),
                    'message': '证据提交已超时'
                })
            elif remaining <= 24:
                alerts.append({
                    'case_id': case_id,
                    'type': 'evidence_urgent',
                    'deadline': evidence_deadline,
                    'remaining_hours': round(remaining, 1),
                    'message': f'证据提交截止剩余 {round(remaining)}h'
                })
        except:
            pass

    # 申诉窗口 21 天
    appeal_deadline = case.get('appeal_deadline')
    if appeal_deadline:
        try:
            deadline = datetime.datetime.fromisoformat(appeal_deadline.replace('Z', '+00:00'))
            remaining = (deadline - now).total_seconds() / 3600 / 24
            if remaining < 0:
                alerts.append({
                    'case_id': case_id,
                    'type': 'appeal_overdue',
                    'deadline': appeal_deadline,
                    'remaining_days': round(remaining, 1),
                    'message': '申诉窗口已关闭'
                })
            elif remaining <= 7:
                alerts.append({
                    'case_id': case_id,
                    'type': 'appeal_warning',
                    'deadline': appeal_deadline,
                    'remaining_days': round(remaining, 1),
                    'message': f'申诉窗口剩余 {round(remaining)} 天'
                })
        except:
            pass

    # 初始售后 4 个工作日响应
    response_deadline = case.get('response_deadline')
    if response_deadline and status in ['open', 'pending']:
        try:
            deadline = datetime.datetime.fromisoformat(response_deadline.replace('Z', '+00:00'))
            remaining = (deadline - now).total_seconds() / 3600
            if remaining <= 24:
                alerts.append({
                    'case_id': case_id,
                    'type': 'response_urgent',
                    'deadline': response_deadline,
                    'remaining_hours': round(remaining, 1),
                    'message': f'售后响应剩余 {round(remaining)}h'
                })
        except:
            pass

alerts.sort(key=lambda x: x.get('remaining_hours', 999))
return alerts
